  // Non-serializable state
  const [localStream, setLocalStream] = useState(null);
  const [remoteStream, setRemoteStream] = useState(null);

  // Serializable state
  const callState = useSelector(state => state.call);

  // Mutable refs for WebRTC & Timers
  const peerConnection = useRef(null);
  const iceCandidatesQueue = useRef([]);
  const timerInterval = useRef(null);
  const ringingTimeoutRef = useRef(null);
  const activeSessionRef = useRef(null);

  // Keep ref in sync for closures
  useEffect(() => { activeSessionRef.current = callState.activeSessionId; }, [callState.activeSessionId]);

  const cleanup = useCallback(() => {
    if (timerInterval.current) clearInterval(timerInterval.current);
    timerInterval.current = null;
    dispatch(setTimeLeft(null));
    dispatch(setIsMinimized(false));

    if (localStream) {
      localStream.getTracks().forEach(track => track.stop());
      setLocalStream(null);
    }
    if (peerConnection.current) {
      peerConnection.current.close();
      peerConnection.current = null;
    }
    setRemoteStream(null);

    dispatch(resetCallState());

    iceCandidatesQueue.current = [];
    if (ringingTimeoutRef.current) clearTimeout(ringingTimeoutRef.current);
    ringingTimeoutRef.current = null;
  }, [localStream, dispatch]);

  const createPeerConnection = useCallback(() => {
    if (peerConnection.current) return peerConnection.current;

    const pc = new RTCPeerConnection({ iceServers: ICE_SERVERS });

    pc.oniceconnectionstatechange = () => {
      if (pc.iceConnectionState === 'failed') pc.restartIce();
      if (pc.iceConnectionState === 'disconnected') {
        setTimeout(() => {
          if (pc.iceConnectionState === 'disconnected') cleanup();
        }, 5000);
      }
    };

    pc.onconnectionstatechange = () => {
      dispatch(setConnectionState(pc.connectionState));
    };

    pc.onicecandidate = (event) => {
      if (event.candidate && activeSessionRef.current) {
        socket.emit('webrtc_signal', { sessionId: activeSessionRef.current, signal: event.candidate });
      }
    };

    pc.onnegotiationneeded = async () => {
      try {
        if (!activeSessionRef.current) return;
        const offer = await pc.createOffer();
        if (pc.signalingState !== 'stable') return;
        await pc.setLocalDescription(offer);
        socket.emit('webrtc_signal', { sessionId: activeSessionRef.current, signal: offer });
      } catch (err) {
        console.error("❌ [NEGOTIATION_ERROR]", err);
      }
    };

    pc.ontrack = (event) => setRemoteStream(event.streams[0]);

    if (localStream) {
      localStream.getTracks().forEach(track => pc.addTrack(track, localStream));
    }

    peerConnection.current = pc;
    return pc;
  }, [localStream, cleanup, dispatch]);

  useEffect(() => {
    if (peerConnection.current && localStream) {
      const senders = peerConnection.current.getSenders();
      localStream.getTracks().forEach(track => {
        if (!senders.find(s => s.track === track)) {
          peerConnection.current.addTrack(track, localStream);
        }
      });
    }
  }, [localStream]);

  // ─── Socket Event Handlers ───
  useEffect(() => {
    if (!token) return;

    const handleIncoming = (data) => {
      dispatch(setIncomingCall(data));
      dispatch(setCallType(data.type));
      dispatch(setActiveSessionId(data.sessionId));

      let avatarUrl = data.callerAvatar;
      if (avatarUrl && !avatarUrl.startsWith('http')) {
        const baseUrl = import.meta.env.VITE_API_BASE_URL?.split('/api')[0] || '';
        avatarUrl = `${baseUrl}/${avatarUrl}`;
      }
      dispatch(setPartnerInfo({ 
        name: data.callerName || 'Unknown', 
        avatar: avatarUrl,
        intakeData: data.intakeData 
      }));

      if (ringingTimeoutRef.current) clearTimeout(ringingTimeoutRef.current);
      ringingTimeoutRef.current = setTimeout(() => respondToCall(false), 45000);
    };

    const handleSignal = async ({ signal }) => {
      const pc = createPeerConnection();
      try {
        if (signal.type === 'offer') {
          await pc.setRemoteDescription(new RTCSessionDescription(signal));
          while (iceCandidatesQueue.current.length > 0) {
            await pc.addIceCandidate(iceCandidatesQueue.current.shift());
          }
          const answer = await pc.createAnswer();
          await pc.setLocalDescription(answer);
          socket.emit('webrtc_signal', { sessionId: activeSessionRef.current, signal: answer });
        } else if (signal.type === 'answer') {
          await pc.setRemoteDescription(new RTCSessionDescription(signal));
          while (iceCandidatesQueue.current.length > 0) {
            await pc.addIceCandidate(iceCandidatesQueue.current.shift());
          }
        } else if (signal.candidate) {
          const candidate = new RTCIceCandidate(signal);
          if (pc.remoteDescription) {
            await pc.addIceCandidate(candidate);
          } else {
            iceCandidatesQueue.current.push(candidate);
          }
        }
      } catch (err) {
        console.error("❌ [SIGNAL_ERROR]", err);
      }
    };

    const handleAnswered = async (data) => {
      if (data.accepted) {
        if (ringingTimeoutRef.current) clearTimeout(ringingTimeoutRef.current);
        ringingTimeoutRef.current = null;
        dispatch(setCallActive(true));
        dispatch(setIsCalling(false));

        if (timerInterval.current) clearInterval(timerInterval.current);
        timerInterval.current = setInterval(() => {
          dispatch((dispatch, getState) => {
             const prev = getState().call.timeLeft;
             dispatch(setTimeLeft(prev > 0 ? prev - 1 : 0));
          });
        }, 1000);
      } else {
        dispatch(setIsCalling(false));
        cleanup();
      }
    };

    const handleSessionStarted = (data) => {
      if (data.timerSeconds !== undefined) dispatch(setTimeLeft(data.timerSeconds));
    };

    const handleBalanceUpdate = (data) => {
      if (data.newBalance !== undefined && user?.role === 'USER') {
        dispatch(updateWalletBalance(data.newBalance));
      }
      if (data.timeLeftSeconds !== undefined) dispatch(setTimeLeft(data.timeLeftSeconds));
    };

    socket.on('incoming_call', handleIncoming);
    socket.on('webrtc_signal', handleSignal);
    socket.on('call_answered', handleAnswered);
    socket.on('call_terminated', cleanup);
    socket.on('session_started', handleSessionStarted);
    socket.on('balance_update', handleBalanceUpdate);

    return () => {
      socket.off('incoming_call', handleIncoming);
      socket.off('webrtc_signal', handleSignal);
      socket.off('call_answered', handleAnswered);
      socket.off('call_terminated', cleanup);
      socket.off('session_started', handleSessionStarted);
      socket.off('balance_update', handleBalanceUpdate);
      if (timerInterval.current) clearInterval(timerInterval.current);
    };
  }, [token, callState.callType, createPeerConnection, cleanup, dispatch, user]);

  const respondToCall = async (accepted) => {
    if (ringingTimeoutRef.current) clearTimeout(ringingTimeoutRef.current);
    ringingTimeoutRef.current = null;

    if (accepted && callState.incomingCall) {
      socket.emit('call_response', { sessionId: activeSessionRef.current, accepted: true });
      dispatch(setCallActive(true));
      dispatch(setIncomingCall(null));

      if (callState.callType === 'chat') {
        navigate(`/chat/${activeSessionRef.current}`);
      } else {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({
            video: callState.callType === 'video',
            audio: true
          });
          setLocalStream(stream);
        } catch (err) {
          console.error("❌ [MEDIA_ERROR]", err);
          socket.emit('call_response', { sessionId: activeSessionRef.current, accepted: false });
          cleanup();
        }
      }
    } else {
      socket.emit('call_response', { sessionId: activeSessionRef.current, accepted: false });
      dispatch(setIncomingCall(null));
      cleanup();
    }
  };

  const initiateCall = async (sessionId, type, partner) => {
    dispatch(setActiveSessionId(sessionId));
    dispatch(setCallType(type));
    dispatch(setIsCalling(true));
    dispatch(setPartnerInfo(partner || { name: 'Partner', avatar: null }));

    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: type === 'video',
        audio: true
      });
      setLocalStream(stream);
      socket.emit('call_initiate', { sessionId, type });

      if (ringingTimeoutRef.current) clearTimeout(ringingTimeoutRef.current);
      ringingTimeoutRef.current = setTimeout(() => endCall(true), 45000);
    } catch (err) {
      dispatch(setIsCalling(false));
      throw err;
    }
  };

  const endCall = (manual = false) => {
    if (manual && activeSessionRef.current) {
      socket.emit('call_end', { sessionId: activeSessionRef.current });
    }
    cleanup();
  };

  const toggleMute = () => {
    if (localStream) {
      const track = localStream.getAudioTracks()[0];
      if (track) {
        track.enabled = !track.enabled;
        dispatch(setIsMuted(!track.enabled));
      }
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      const track = localStream.getVideoTracks()[0];
      if (track) {
        track.enabled = !track.enabled;
        dispatch(setIsVideoOff(!track.enabled));
      }
    }
  };

  const handleSetIsMinimized = (val) => dispatch(setIsMinimized(val));

  const providerValue = {
    localStream,
    remoteStream,
    initiateCall,
    respondToCall,
    endCall,
    toggleMute,
    toggleVideo,
    setIsMinimized: handleSetIsMinimized
  };

  return (
    <CallContext.Provider value={providerValue}>
      {children}
    </CallContext.Provider>
  );
};

export const useCall = () => {
  const context = useContext(CallContext);
  const callState = useSelector(state => state.call);

  if (!context) {
    throw new Error('useCall must be used within a CallProvider');
  }

  return useMemo(() => ({
    ...context,
    ...callState
  }), [context, callState]);
};

import React, { createContext, useContext, useEffect, useCallback, useMemo } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import socket from '../lib/socket';
import { useAuth } from './AuthContext';
import IntakeForm from '../components/IntakeForm';
import { toast } from 'react-hot-toast';
import { useNavigate } from 'react-router-dom';
import api from '../lib/api';

import { 
    setSessions, 
    setCurrentMessages, 
    addMessage, 
    updateMessageStatus, 
    setActiveSessionId, 
    setPendingRitualRequest, 
    setIsChatOpen, 
    setMinimized, 
    setIntakeConfig, 
    updateSessionInList 
} from '../store/slices/chatSlice';

import { fetchSessions, fetchMessages, endSession } from '../store/thunks/chatThunks';
import { updateWalletBalance } from '../store/slices/authSlice';

const ChatContext = createContext();

export const ChatProvider = ({ children }) => {
    const dispatch = useDispatch();
    const { user, token } = useAuth();
    const { activeSessionId, intakeConfig } = useSelector(state => state.chat);
    const navigate = useNavigate();

    // ─── Socket Event Handlers ───
    useEffect(() => {
        if (!token) {
            if (socket.connected) socket.disconnect();
            return;
        }

        const onConnect = () => {
            if (user?.role === 'EXPERT') {
                const expertId = user.expert?.id || user.id;
                socket.emit('join_portal', expertId);
            }
            if (activeSessionId) {
                socket.emit('join_chat', { sessionId: activeSessionId });
                socket.emit('mark_read', { sessionId: activeSessionId });
            }
        };

        const handleNewMessage = (msg) => {
            if (activeSessionId === msg.sessionId) {
                dispatch(addMessage(msg));
                socket.emit('mark_read', { sessionId: msg.sessionId });
            }

            // Update sidebar session unread count
            dispatch((dispatch, getState) => {
                const { sessions } = getState().chat;
                const existingIndex = sessions.findIndex(s => s.id === msg.sessionId);
                if (existingIndex !== -1) {
                    const session = { ...sessions[existingIndex] };
                    session.updatedAt = new Date().toISOString();
                    session.messages = [msg];
                    session._unreadCount = (session._unreadCount || 0) + (activeSessionId === msg.sessionId ? 0 : 1);
                    dispatch(updateSessionInList(session));
                    // Re-sort after updating
                    const updatedSessions = [...getState().chat.sessions].sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
                    dispatch(setSessions(updatedSessions));
                }
            });
        };

        const handleNewRequest = ({ session }) => {
            if (user?.role === 'EXPERT' && (session.type === 'CHAT' || !session.type)) {
                dispatch((dispatch, getState) => {
                    const { sessions } = getState().chat;
                    dispatch(setSessions([session, ...sessions]));
                });
                dispatch(setPendingRitualRequest(session));
                socket.emit('join_chat', { sessionId: session.id });
            }
        };

        const handleEnded = (data) => {
            dispatch((dispatch, getState) => {
                const { sessions } = getState().chat;
                const session = sessions.find(s => s.id === data.sessionId);
                if (session) {
                    dispatch(updateSessionInList({ ...session, status: 'COMPLETED' }));
                }
            });
        };

        const handleRead = ({ sessionId }) => {
            if (activeSessionId === sessionId) {
                dispatch((dispatch, getState) => {
                    const { currentMessages } = getState().chat;
                    dispatch(setCurrentMessages(currentMessages.map(m => ({ ...m, isRead: true }))));
                });
            }
        };

        const handleReaction = ({ messageId, reaction }) => {
            dispatch((dispatch, getState) => {
                const { currentMessages } = getState().chat;
                dispatch(setCurrentMessages(currentMessages.map(m => m.id === messageId ? { ...m, reaction } : m)));
            });
        };

        const handleBalance = (data) => {
            if (data.newBalance !== undefined) {
                dispatch(updateWalletBalance(data.newBalance));
            }
        };

        socket.on('connect', onConnect);
        socket.on('new_message', handleNewMessage);
        socket.on('new_ritual_request', handleNewRequest);
        socket.on('session_ended', handleEnded);
        socket.on('force_disconnect', handleEnded);
        socket.on('messages_read', handleRead);
        socket.on('react_message', handleReaction);
        socket.on('balance_update', handleBalance);

        if (socket.connected) onConnect();

        return () => {
            socket.off('connect', onConnect);
            socket.off('new_message', handleNewMessage);
            socket.off('new_ritual_request', handleNewRequest);
            socket.off('session_ended', handleEnded);
            socket.off('force_disconnect', handleEnded);
            socket.off('messages_read', handleRead);
            socket.off('react_message', handleReaction);
            socket.off('balance_update', handleBalance);
        };
    }, [token, activeSessionId, user, dispatch]);

    // Initial fetch
    useEffect(() => { 
        if (token && user?.id) {
            dispatch(fetchSessions()); 
        }
    }, [token, user?.id, dispatch]);

    const handleIntakeSubmit = async (formData) => {
        try {
            const startRes = await api.post('/chat/start', {
                expertId: intakeConfig.expertId,
                intakeData: formData,
                isRandom: intakeConfig.isRandom,
                type: intakeConfig.sessionType
            });
            const session = startRes.data.data.session || startRes.data.data;

            const path = `/chat/${session.id}?autoCall=true&type=${intakeConfig.sessionType.toLowerCase()}`;
            navigate(path);

            dispatch(setIntakeConfig({ isOpen: false }));
            toast.success("Connecting with your spiritual guide...");
        } catch (err) {
            console.error("Intake submission failed:", err);
            toast.error(err.response?.data?.message || "Failed to start session. Please try again.");
            throw err;
        }
    };

    return (
        <ChatContext.Provider value={{}}>
            {children}
            <IntakeForm 
                isOpen={intakeConfig.isOpen}
                onClose={() => dispatch(setIntakeConfig({ isOpen: false }))}
                onSubmit={handleIntakeSubmit}
                expert={intakeConfig.expert}
                isRandom={intakeConfig.isRandom}
            />
        </ChatContext.Provider>
    );
};

// ─── Custom Hook Replacement for useChat ───
export const useChat = () => {
    const dispatch = useDispatch();
    const chatState = useSelector(state => state.chat);
    const { user } = useAuth();

    const fetchSessionsWrapped = useCallback(() => dispatch(fetchSessions()), [dispatch]);
    const fetchMessagesWrapped = useCallback((sessionId) => dispatch(fetchMessages(sessionId)), [dispatch]);

    const sendMessage = useCallback((sessionId, content, type = 'TEXT', overrideSenderId = null) => {
        if (!socket.connected) socket.connect();

        const tempId = Date.now().toString();
        const optimisticMsg = {
            id: tempId,
            sessionId,
            senderId: overrideSenderId || user.id,
            content,
            messageType: type,
            createdAt: new Date().toISOString(),
            isRead: false,
            isOptimistic: true,
            sender: { name: user.name, avatar: user.avatar, role: user.role }
        };

        if (chatState.activeSessionId === sessionId) {
            dispatch(addMessage(optimisticMsg));
        }

        socket.emit('send_message', {
            sessionId,
            content,
            messageType: type,
            overrideSenderId,
        });
    }, [user, chatState.activeSessionId, dispatch]);

    const reactToMessage = useCallback((messageId, reaction) => {
        if (!socket.connected) return;
        dispatch((dispatch, getState) => {
            const { currentMessages } = getState().chat;
            dispatch(setCurrentMessages(currentMessages.map(m => m.id === messageId ? { ...m, reaction } : m)));
        });
        socket.emit('react_message', { messageId, reaction });
    }, [dispatch]);

    const clearUnread = useCallback((sessionId) => {
        dispatch((dispatch, getState) => {
            const { sessions } = getState().chat;
            const session = sessions.find(s => s.id === sessionId);
            if (session) {
                dispatch(updateSessionInList({ ...session, _unreadCount: 0 }));
            }
        });
    }, [dispatch]);

    const openChat = useCallback((sessionId) => {
        dispatch(setActiveSessionId(sessionId));
        dispatch(setIsChatOpen(true));
        dispatch(setMinimized(false));
        clearUnread(sessionId);
    }, [dispatch, clearUnread]);

    const closeChat = useCallback(() => {
        dispatch(setIsChatOpen(false));
        dispatch(setMinimized(false));
    }, [dispatch]);

    const startAndOpenChat = useCallback((expertId, expertData, isRandom = false, sessionType = 'CHAT') => {
        dispatch(setIntakeConfig({
            isOpen: true,
            expertId,
            expert: expertData,
            isRandom,
            sessionType
        }));
    }, [dispatch]);

    const rejectRitual = useCallback(async (sessionId) => {
        try {
            await dispatch(endSession(sessionId)).unwrap();
            dispatch(setPendingRitualRequest(null));
        } catch (err) {
            console.error("❌ [REJECT_RITUAL_ERROR]", err);
            dispatch(setPendingRitualRequest(null));
        }
    }, [dispatch]);

    const acceptRitual = useCallback((sessionId) => {
        dispatch(setPendingRitualRequest(null));
        window.location.href = `/expert/chat/${sessionId}`;
    }, [dispatch]);

    // Expose setters
    const setSessionId = useCallback((id) => dispatch(setActiveSessionId(id)), [dispatch]);
    const setChatOpen = useCallback((isOpen) => dispatch(setIsChatOpen(isOpen)), [dispatch]);
    const setChatMinimized = useCallback((isMin) => dispatch(setMinimized(isMin)), [dispatch]);

    return useMemo(() => ({
        ...chatState,
        setActiveSessionId: setSessionId,
        setIsChatOpen: setChatOpen,
        setMinimized: setChatMinimized,
        openChat,
        closeChat,
        startAndOpenChat,
        clearUnread,
        fetchMessages: fetchMessagesWrapped,
        fetchSessions: fetchSessionsWrapped,
        sendMessage,
        reactToMessage,
        acceptRitual,
        rejectRitual
    }), [
        chatState, setSessionId, setChatOpen, setChatMinimized,
        openChat, closeChat, startAndOpenChat, clearUnread,
        fetchMessagesWrapped, fetchSessionsWrapped, sendMessage, reactToMessage,
        acceptRitual, rejectRitual
    ]);
};

import React, { createContext, useContext, useState, useEffect } from "react";

const LanguageContext = createContext();

export const LanguageProvider = ({ children }) => {
  // Check local storage or default to 'default'
  const [language, setLanguage] = useState(() => {
    return localStorage.getItem("appLanguage") || "default";
  });

  useEffect(() => {
    localStorage.setItem("appLanguage", language);
  }, [language]);

  const toggleLanguage = (lang) => {
    setLanguage(lang);
  };

  return (
    <LanguageContext.Provider value={{ language, toggleLanguage }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error("useLanguage must be used within a LanguageProvider");
  }
  return context;
};

import React, { createContext, useContext, useEffect, useCallback, useMemo } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useAuth } from './AuthContext';
import socket from '../lib/socket';
import { 
  fetchUnreadCount, 
  fetchNotifications as thunkFetchNotifications, 
  markAsRead as thunkMarkAsRead, 
  markAllRead as thunkMarkAllRead, 
  deleteNotification as thunkDeleteNotification 
} from '../store/thunks/notificationThunks';
import { setUnreadCount, setNotifications } from '../store/slices/notificationSlice';

const NotificationContext = createContext();

export const NotificationProvider = ({ children }) => {
  const dispatch = useDispatch();
  const { token } = useAuth();

  useEffect(() => {
    if (token) {
      dispatch(fetchUnreadCount());

      const handleNewNotification = () => {
        dispatch(fetchUnreadCount());
      };

      // Real-time synchronization
      socket.on('new_notification', handleNewNotification);

      return () => {
        socket.off('new_notification', handleNewNotification);
      };
    } else {
      dispatch(setUnreadCount(0));
      dispatch(setNotifications([]));
    }
  }, [token, dispatch]);

  return (
    <NotificationContext.Provider value={{}}>
      {children}
    </NotificationContext.Provider>
  );
};

export const useNotifications = () => {
  const dispatch = useDispatch();
  const { notifications, unreadCount, loading } = useSelector(state => state.notification);

  const fetchNotifications = useCallback(async (page = 1, limit = 10) => {
    return dispatch(thunkFetchNotifications({ page, limit })).unwrap();
  }, [dispatch]);

  const markAsRead = useCallback(async (id) => {
    return dispatch(thunkMarkAsRead(id)).unwrap();
  }, [dispatch]);

  const markAllRead = useCallback(async () => {
    return dispatch(thunkMarkAllRead()).unwrap();
  }, [dispatch]);

  const deleteNotification = useCallback(async (id) => {
    return dispatch(thunkDeleteNotification(id)).unwrap();
  }, [dispatch]);

  const refreshCount = useCallback(() => {
    dispatch(fetchUnreadCount());
  }, [dispatch]);

  return useMemo(() => ({
    notifications,
    unreadCount,
    loading,
    fetchNotifications,
    markAsRead,
    markAllRead,
    deleteNotification,
    refreshCount
  }), [
    notifications, unreadCount, loading,
    fetchNotifications, markAsRead, markAllRead, deleteNotification, refreshCount
  ]);
};

import React, { createContext, useContext, useState, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Sparkles, AlertCircle, CheckCircle2, X } from "lucide-react";

const ToastContext = createContext();

/**
 * Premium Sanctuary Alerts - Spiritual Notification Matrix
 * Replaces standard browser alerts with elegant, animated toasts.
 */
export const ToastProvider = ({ children }) => {
    const [toasts, setToasts] = useState([]);

    const addToast = useCallback((message, type = "success") => {
        const id = Math.random().toString(36).substr(2, 9);
        setToasts((prev) => [...prev, { id, message, type }]);

        // Auto-dissolve after 5 cosmic seconds
        setTimeout(() => {
            setToasts((prev) => prev.filter((t) => t.id !== id));
        }, 5000);
    }, []);

    const removeToast = (id) => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
    };

    return (
        <ToastContext.Provider value={{ toast: addToast }}>
            {children}
            {/* The Toast Sanctuary - Rendering Layer */}
            <div className="fixed top-10 right-10 z-[1000] flex flex-col gap-2.5 pointer-events-none">
                <AnimatePresence>
                    {toasts.map((t) => (
                        <motion.div
                            key={t.id}
                            initial={{ opacity: 0, y: -20, scale: 0.9, x: 20 }}
                            animate={{ opacity: 1, y: 0, scale: 1, x: 0 }}
                            exit={{ opacity: 0, scale: 0.8, x: 20, transition: { duration: 0.2 } }}
                            className={`pointer-events-auto min-w-[300px] max-w-md py-3.5 px-5 rounded-2xl border bg-black/80 backdrop-blur-3xl shadow-2xl flex items-center justify-between gap-4 group overflow-hidden relative ${
                                t.type === "success" ? "border-emerald-500/20 shadow-emerald-500/10" : "border-rose-500/20 shadow-rose-500/10"
                            }`}
                        >
                            <div className="flex items-center gap-4 relative z-10">
                                <div className={`w-9 h-9 rounded-xl flex items-center justify-center shadow-xl ${
                                    t.type === "success" ? "bg-emerald-500/10 text-emerald-400 border border-emerald-500/20" : "bg-rose-500/10 text-rose-400 border border-rose-500/20"
                                }`}>
                                     {t.type === "success" ? <CheckCircle2 size={18} /> : <AlertCircle size={18} />}
                                </div>
                                <div className="space-y-0.5">
                                     <p className="text-[13px] font-sans font-semibold text-white tracking-wide leading-snug">{t.message}</p>
                                </div>
                            </div>

                            <button 
                                onClick={() => removeToast(t.id)}
                                className="p-2 text-white/40 hover:text-white transition-colors relative z-10"
                            >
                                <X size={16} />
                            </button>
                        </motion.div>
                    ))}
                </AnimatePresence>
            </div>
        </ToastContext.Provider>
    );
};

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) throw new Error("useToast must be used within ToastProvider");
    return context;
};

import { useState, useEffect, useRef, useCallback } from 'react';
import socket from '../lib/socket';

export const useWebRTCCall = (sessionId, user) => {
  const [localStream, setLocalStream] = useState(null);
  const [remoteStream, setRemoteStream] = useState(null);
  const [callActive, setCallActive] = useState(false);
  const [isCalling, setIsCalling] = useState(false);
  const [incomingCall, setIncomingCall] = useState(null);
  const [callType, setCallType] = useState(null);
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);

  const peerConnection = useRef(null);
  const iceCandidatesQueue = useRef([]);

  const cleanup = useCallback(() => {
    if (localStream) {
      localStream.getTracks().forEach(track => track.stop());
      setLocalStream(null);
    }
    if (peerConnection.current) {
      peerConnection.current.close();
      peerConnection.current = null;
    }
    setRemoteStream(null);
    setCallActive(false);
    setIsCalling(false);
    setIncomingCall(null);
    setIsMuted(false);
    setIsVideoOff(false);
    iceCandidatesQueue.current = [];
  }, [localStream]);

  const createPeerConnection = useCallback(() => {
    if (peerConnection.current) return peerConnection.current;

    const configuration = {
      iceServers: [{ urls: 'stun:stun.l.google.com:19302' }]
    };

    const pc = new RTCPeerConnection(configuration);

    pc.onicecandidate = (event) => {
      if (event.candidate) {
        socket.emit('webrtc_signal', { sessionId, signal: event.candidate });
      }
    };

    pc.onnegotiationneeded = async () => {
      try {
        const offer = await pc.createOffer();
        await pc.setLocalDescription(offer);
        socket.emit('webrtc_signal', { sessionId, signal: offer });
      } catch (err) {
        console.error("🌌 [NEGOTIATION_ERROR]", err);
      }
    };

    pc.ontrack = (event) => {
      console.log("🌌 [REMOTE_TRACK_RECEIVED]", event.streams[0]);
      setRemoteStream(event.streams[0]);
    };

    if (localStream) {
      localStream.getTracks().forEach(track => pc.addTrack(track, localStream));
    }

    peerConnection.current = pc;
    return pc;
  }, [sessionId, localStream]);

  // Effect to handle tracks adding if pc is created before localStream is ready
  useEffect(() => {
    if (peerConnection.current && localStream) {
      localStream.getTracks().forEach(track => {
        const senders = peerConnection.current.getSenders();
        const alreadyAdded = senders.find(s => s.track === track);
        if (!alreadyAdded) {
          peerConnection.current.addTrack(track, localStream);
        }
      });
    }
  }, [localStream]);

  const initiateCall = async (type) => {
    setCallType(type);
    setIsCalling(true);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: type === 'video',
        audio: true
      });
      setLocalStream(stream);
      socket.emit('call_initiate', { sessionId, type });
    } catch (err) {
      console.error("⚠️ [MEDIA_ERROR]", err);
      setIsCalling(false);
      throw err;
    }
  };

  const respondToCall = async (accepted) => {
    if (accepted) {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: callType === 'video',
          audio: true
        });
        setLocalStream(stream);
      } catch (err) {
        console.error("⚠️ [MEDIA_ERROR]", err);
        socket.emit('call_response', { sessionId, accepted: false });
        return;
      }
    }

    socket.emit('call_response', { sessionId, accepted });

    if (accepted) {
      setCallActive(true);
      setIncomingCall(null);
      if (callType === 'video') createPeerConnection();
    } else {
      setIncomingCall(null);
    }
  };

  const endCall = (manual = false) => {
    if (manual) {
      socket.emit('call_end', { sessionId });
      socket.emit('end_session', { sessionId });
    }
    cleanup();
  };

  const toggleMute = () => {
    if (localStream) {
      const audioTrack = localStream.getAudioTracks()[0];
      if (audioTrack) {
        audioTrack.enabled = !audioTrack.enabled;
        setIsMuted(!audioTrack.enabled);
      }
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      const videoTrack = localStream.getVideoTracks()[0];
      if (videoTrack) {
        videoTrack.enabled = !videoTrack.enabled;
        setIsVideoOff(!videoTrack.enabled);
      }
    }
  };

  useEffect(() => {
    const handleSignal = async ({ signal }) => {
      const pc = createPeerConnection();
      try {
        if (signal.type === 'offer') {
          await pc.setRemoteDescription(new RTCSessionDescription(signal));
          while (iceCandidatesQueue.current.length > 0) {
            const cand = iceCandidatesQueue.current.shift();
            await pc.addIceCandidate(cand);
          }
          const answer = await pc.createAnswer();
          await pc.setLocalDescription(answer);
          socket.emit('webrtc_signal', { sessionId, signal: answer });
        } else if (signal.type === 'answer') {
          await pc.setRemoteDescription(new RTCSessionDescription(signal));
          while (iceCandidatesQueue.current.length > 0) {
            const cand = iceCandidatesQueue.current.shift();
            await pc.addIceCandidate(cand);
          }
        } else if (signal.candidate) {
          const candidate = new RTCIceCandidate(signal);
          if (pc.remoteDescription) {
            await pc.addIceCandidate(candidate);
          } else {
            iceCandidatesQueue.current.push(candidate);
          }
        }
      } catch (err) {
        console.error("🌌 [SIGNAL_ERROR]", err);
      }
    };

    const handleAnswered = async (data) => {
      if (data.accepted) {
        setCallActive(true);
        setIsCalling(false);
        if (callType === 'video') {
          const pc = createPeerConnection();
          const offer = await pc.createOffer();
          await pc.setLocalDescription(offer);
          socket.emit('webrtc_signal', { sessionId, signal: offer });
        }
      } else {
        setIsCalling(false);
        cleanup();
      }
    };

    socket.on('webrtc_signal', handleSignal);
    socket.on('call_answered', handleAnswered);
    socket.on('incoming_call', (data) => {
      if (data.sessionId === sessionId) {
        setIncomingCall(data);
        setCallType(data.type);
      }
    });
    socket.on('call_terminated', () => cleanup());

    return () => {
      socket.off('webrtc_signal', handleSignal);
      socket.off('call_answered', handleAnswered);
      socket.off('incoming_call');
      socket.off('call_terminated');
    };
  }, [sessionId, callType, createPeerConnection, cleanup]);

  return {
    localStream,
    remoteStream,
    callActive,
    isCalling,
    incomingCall,
    callType,
    isMuted,
    isVideoOff,
    initiateCall,
    respondToCall,
    endCall,
    toggleMute,
    toggleVideo,
    cleanup
  };
};

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X } from "lucide-react";
import Sidebar from "../components/Sidebar";
import { useAuth } from "../context/AuthContext";

/**
 * DashboardLayout - Adaptive container for internal pages.
 * Leverages the global Top Navbar for primary navigation.
 * Keeps the Sidebar ONLY for Admins.
 */
const DashboardLayout = ({ children }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const { user } = useAuth();
  const isAdmin = user?.role === "ADMIN";

  return (
    <div className="min-h-screen bg-black text-white relative flex overflow-hidden font-sans">
      {/* Dynamic Background */}
      <div className="fixed inset-0 z-0 text-white">
        <img 
          src="/dashboard_bg.png" 
          alt="Cosmic Background" 
          className="w-full h-full object-cover opacity-20"
        />
        <div className="absolute inset-0 bg-linear-to-b from-black/80 via-black/20 to-black" />
      </div>

      {/* Internal Admin Sidebar */}
      {isAdmin && (
        <aside className="hidden md:block w-72 lg:w-80 h-screen sticky top-0 z-50 shrink-0 border-r border-white/5">
          <Sidebar />
        </aside>
      )}

      {/* Mobile Sidebar Toggle (Only for Admin when regular Navbar is not enough) */}
      {isAdmin && (
        <div className="fixed bottom-6 right-6 z-150 md:hidden">
            <button 
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                className="w-14 h-14 bg-purple-600 rounded-full flex items-center justify-center shadow-2xl shadow-purple-500/40"
            >
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
        </div>
      )}

      {/* Mobile Drawer (Only for Admin) */}
      <AnimatePresence>
        {isAdmin && isMobileMenuOpen && (
          <motion.aside
            initial={{ x: "-100%" }}
            animate={{ x: 0 }}
            exit={{ x: "-100%" }}
            transition={{ type: "spring", damping: 25, stiffness: 200 }}
            className="fixed inset-0 z-200 w-72 h-screen"
          >
            <Sidebar closeMenu={() => setIsMobileMenuOpen(false)} />
          </motion.aside>
        )}
      </AnimatePresence>

      {/* Main Content Area - Significant top padding to clear Global Navbar */}
      <main className={`flex-1 h-screen overflow-y-auto no-scrollbar relative z-10 flex flex-col pt-24 pb-20`}>
        <div className="max-w-6xl mx-auto w-full px-6 md:px-12 py-8">
          {children}
        </div>
      </main>
    </div>
  );
};

export default DashboardLayout;

import { initializeApp } from 'firebase/app';
import { getAuth } from 'firebase/auth';
import { getMessaging, getToken, onMessage } from 'firebase/messaging';

const firebaseConfig = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
  authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
  storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: import.meta.env.VITE_FIREBASE_APP_ID,
  measurementId: import.meta.env.VITE_FIREBASE_MEASUREMENT_ID
};

const app = initializeApp(firebaseConfig);
const auth = getAuth(app);

let messaging = null;
try {
  messaging = getMessaging(app);
} catch (err) {
  console.warn('Firebase messaging not supported in this browser');
}

/**
 * Request push notification permission and get FCM token
 */
export const requestNotificationPermission = async () => {
  try {
    if (!messaging) return null;

    const permission = await Notification.requestPermission();
    if (permission !== 'granted') return null;

    const token = await getToken(messaging, {
      vapidKey: import.meta.env.VITE_FIREBASE_VAPID_KEY || ''
    });

    return token;
  } catch (err) {
    console.error('FCM token error:', err);
    return null;
  }
};

/**
 * Listen for foreground push notifications
 */
export const onForegroundMessage = (callback) => {
  if (!messaging) return () => {};
  return onMessage(messaging, callback);
};

export { app, messaging, auth };

