              </div>
              <div>
                <p className="text-xs font-bold text-amber-500 tracking-tight">Low Balance Warning</p>
                <p className="text-[10px] text-amber-500/70">Recharge now to continue uninterrupted consultations.</p>
              </div>
            </div>
            <button 
              onClick={() => navigate("/wallet")}
              className="text-[10px] font-bold text-amber-500 border-b border-amber-500/30 hover:border-amber-500 transition-all"
            >
              Recharge ₹
            </button>
          </motion.div>
        )}

        {/* Join as Expert CTA (SRS §8) */}
        {user?.role === 'USER' && (
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            onClick={() => navigate("/expert-signup")}
            className="group relative p-8 rounded-[3rem] bg-[#0c0c14] border border-white/5 overflow-hidden cursor-pointer hover:border-purple-500/30 transition-all shadow-2xl"
          >
             <div className="absolute top-0 right-0 w-64 h-64 bg-purple-600/5 blur-[80px] -mr-32 -mt-32 group-hover:bg-purple-600/10 transition-all duration-700" />
             <div className="relative z-10 flex flex-col md:flex-row items-center gap-8">
                <div className="w-20 h-20 rounded-[2rem] bg-purple-600/10 border border-purple-500/20 flex items-center justify-center group-hover:rotate-6 transition-transform">
                   <Sparkles className="text-purple-400" size={32} />
                </div>
                <div className="flex-1 text-center md:text-left">
                   <h3 className="text-xl font-bold text-white tracking-tight italic">Share Your <span className="text-purple-400">Cosmic Wisdom</span></h3>
                   <p className="text-xs text-white/50 mt-2 font-medium">Join the Sanctuary as an Expert. Guide seekers through their darkest hours and earn while you heal.</p>
                </div>
                <div className="px-8 py-4 bg-white/5 border border-white/10 rounded-2xl text-[10px] font-bold tracking-widest uppercase hover:bg-white/10 transition-all flex items-center gap-3">
                   Apply Now <ArrowRight size={14} className="group-hover:translate-x-2 transition-transform" />
                </div>
             </div>
          </motion.div>
        )}

        {/* Stats Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
          {stats.map((stat, index) => (
            <motion.div
              key={stat.title}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.1 }}
              className="bg-white/5 border border-white/5 rounded-2xl p-5 hover:bg-white/10 transition-colors relative overflow-hidden group"
            >
              <div className="flex items-center gap-4 relative z-10">
                <div className={`w-10 h-10 ${stat.bg} rounded-lg flex items-center justify-center border border-white/5`}>
                  <stat.icon size={18} className={stat.color} />
                </div>
                <div>
                  <p className="text-[9px]  tracking-widest text-white/70 font-semibold mb-0.5">{stat.title}</p>
                  <p className="text-xl font-semibold text-white/90">{stat.value}</p>
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Recent Activity Mini List */}
        <section className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-sm font-semibold  tracking-widest text-white/85">Recent History</h2>
            <button 
              onClick={() => navigate("/transactions")}
              className="text-[10px] font-semibold  tracking-widest text-purple-400 hover:text-purple-300 transition-colors"
            >
              View Full Index
            </button>
          </div>
          
          <div className="space-y-2">
            {loading ? (
                <div className="py-10 text-center opacity-20 italic font-light tracking-widest text-[9px] ">Consulting Memory...</div>
            ) : history.length > 0 ? (
                (() => {
                    // Group by Expert ID to show "User-wise" not "Session-wise"
                    const uniqueExperts = [];
                    const seenExperts = new Set();
                    
                    history.forEach(item => {
                        const expertId = item.expertId;
                        if (!seenExperts.has(expertId)) {
                            seenExperts.add(expertId);
                            uniqueExperts.push(item);
                        }
                    });

                    return uniqueExperts.map((item) => {
                      const isSeeker = user?.id === item.userId;
                      const otherParty = isSeeker ? item.expert?.user : item.user;
                      const displayName = (item.isAnonymous && !isSeeker) ? "Anonymous Soul" : (otherParty?.name || item.expert?.displayName || "Unknown");
                      
                      const isLocked = !item.isUnlocked && item.totalMessages > 0;
                      const hasAdmin = !!item.adminInterventionId;
                      
                      return (
                        <div 
                          key={item.id} 
                          onClick={() => navigate(`/chat/${item.id}`)}
                          className={`bg-white/5 border border-white/5 rounded-xl p-3 flex items-center justify-between hover:bg-white/8 transition-colors group cursor-pointer transition-all ${isLocked ? 'opacity-70' : ''}`}
                        >
                          <div className="flex items-center gap-3">
                            <div className="relative">
                                <div className="w-8 h-8 rounded-lg overflow-hidden border border-white/5 shrink-0 bg-purple-500/10 flex items-center justify-center">
                                {otherParty?.avatar || item.expert?.profileImage ? (
                                    <img src={otherParty?.avatar || item.expert?.profileImage} className="w-full h-full object-cover opacity-80" alt="" />
                                ) : (
                                    <MessageSquare size={14} className="text-purple-400" />
                                )}
                                </div>
                                {hasAdmin && (
                                    <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full flex items-center justify-center border border-[#06070f] shadow-lg">
                                        <ShieldAlert size={8} className="text-white" />
                                    </div>
                                )}
                            </div>
                            <div>
                              <div className="flex items-center gap-2">
                                <h4 className="text-[11px] font-semibold text-gray-200 tracking-tight">{displayName}</h4>
                                {isLocked ? (
                                    <Lock size={10} className="text-amber-500/60" />
                                ) : item.totalMessages > 0 ? (
                                    <Unlock size={10} className="text-emerald-500/60" />
                                ) : null}
                              </div>
                              <p className="text-[9px] text-gray-600 font-semibold mt-0.5">
                                  {new Date(item.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })} • {item.status}
                                  {isLocked && <span className="text-amber-500/70 ml-1"> (Locked)</span>}
                              </p>
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <div className="text-right">
                               <p className="text-[10px] font-semibold text-white/85">₹{item.totalAmount || 0}</p>
                               {item.durationMinutes > 0 && <p className="text-[8px] text-gray-700 font-semibold">{item.durationMinutes}m</p>}
                            </div>
                            <ChevronRight size={12} className="text-white/40 group-hover:text-white transition-all ml-1" />
                          </div>
                        </div>
                      );
                    });
                })()
            ) : (
                <div className="py-10 text-center opacity-30 italic font-light tracking-widest text-[9px] ">No recent sessions found</div>
            )}
          </div>
        </section>
      </div>
    </DashboardLayout>
  );
};

export default Dashboard;

import React, { useState, useEffect } from "react";
import { 
  Search, 
  MessageSquare, 
  Phone, 
  Video, 
  CheckCircle, 
  Star, 
  ChevronRight,
  User,
  ArrowLeft,
  Languages,
  Briefcase
} from "lucide-react";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../context/ToastContext";
import { useNavigate } from "react-router-dom";
import { motion as m, AnimatePresence } from "framer-motion";
import { useCall } from "../context/CallContext";
import IntakeForm from "../components/IntakeForm";

const DilKiBaat = () => {
    const navigate = useNavigate();
    const { token, api, setIsLoginModalOpen } = useAuth();
    const { toast } = useToast();
    const { initiateCall, callActive } = useCall();

    const [listeners, setListeners] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [activeFilter, setActiveFilter] = useState("all");

    // Intake Form State
    const [isIntakeOpen, setIsIntakeOpen] = useState(false);
    const [intakeExpert, setIntakeExpert] = useState(null);
    const [intakeType, setIntakeType] = useState('CHAT');

    const [filters, setFilters] = useState([
        { id: "all", label: "all experts" },
        { id: "online", label: "currently online" },
        { id: "top", label: "top rated" }
    ]);

    const fetchListeners = async () => {
        try {
            setLoading(true);
            const res = await api.get("/experts?category=dilkibaat");
            setListeners(res.data.data.experts || []);
        } catch (err) {
            console.error("🌌 [FETCH_ERROR]", err);
            toast("failed to load experts", "error");
        } finally {
            setLoading(false);
        }
    };

    const fetchMetadata = async () => {
        try {
            const res = await api.get("/experts/meta/categories");
            const dilCat = res.data.data.find(c => c.code === 'dilkibaat');
            if (dilCat) {
                const dynamicFilters = [
                    { id: "all", label: "all experts" },
                    { id: "online", label: "currently online" },
                    { id: "top", label: "top rated" },
                    ...dilCat.skills.map(s => ({ id: s.name.toLowerCase(), label: s.name.toLowerCase() }))
                ];
                setFilters(dynamicFilters);
            }
        } catch (err) {
            console.error("Meta load failed");
        }
    };

    useEffect(() => {
        fetchListeners();
        fetchMetadata();
    }, []);

    const openIntake = (expert, type) => {
        if (!token) {
            setIsLoginModalOpen(true);
            return;
        }
        setIntakeExpert(expert);
        setIntakeType(type);
        setIsIntakeOpen(true);
    };

    const handleIntakeSubmit = async (formData) => {
        try {
            const res = await api.post("/chat/start", { 
                expertId: intakeExpert._id || intakeExpert.id, 
                type: intakeType,
                intakeData: formData
            });
            const session = res.data.data.session;
            let url = `/chat/${session.id}`;
            
            if (intakeType === 'CALL' || intakeType === 'VIDEO') {
                url += `?autoCall=true&type=${intakeType === 'VIDEO' ? 'video' : 'voice'}`;
                if (!callActive) {
                    const partnerInfo = {
                        name: intakeExpert.displayName || "Expert",
                        avatar: intakeExpert.profileImage || null
                    };
                    initiateCall(session.id, intakeType === 'VIDEO' ? 'video' : 'voice', partnerInfo);
                }
            }
            navigate(url);
        } catch (err) {
            toast(err.response?.data?.message || "expert is busy", "error");
        } finally {
            setIsIntakeOpen(false);
        }
    };

    const filteredListeners = listeners.filter(listener => {
        const displayName = listener.displayName || "Expert";
        const matchesSearch = displayName.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesCategory = listener.category === 'dilkibaat';
        
        if (activeFilter === "online") return matchesSearch && listener.isOnline && matchesCategory;
        if (activeFilter === "top") return matchesSearch && listener.avgRating >= 4.5 && matchesCategory;
        if (activeFilter === "all") return matchesSearch && matchesCategory;
        
        // Skill matching
        const matchesSkill = (listener.specializations || []).some(s => s.toLowerCase() === activeFilter);
        return matchesSearch && matchesCategory && matchesSkill;
    });

    return (
      <div className="min-h-screen bg-[#0d0f17] text-[#e2e8f0] pb-24">
        <IntakeForm isOpen={isIntakeOpen} onClose={() => setIsIntakeOpen(false)} onSubmit={handleIntakeSubmit} expert={intakeExpert} />

        <div className="relative z-10 max-w-7xl mx-auto px-4 md:px-6">
          <header className="pt-24 md:pt-32 pb-12">
            <button 
                onClick={() => navigate(-1)}
                className="flex items-center gap-2 text-slate-500 hover:text-white transition-all mb-8 group"
            >
                <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
                <span className="text-xs font-medium ">back</span>
            </button>

            <div className="flex flex-col md:flex-row md:items-end justify-between gap-8">
              <div className="space-y-3">
                <h1 className="text-4xl md:text-5xl font-medium tracking-tight text-white ">Dil Ki Baat</h1>
                <p className="text-slate-400 text-lg font-light  max-w-xl leading-relaxed">
                  connect with verified professionals for personalized consultation and guidance.
                </p>
              </div>

              <div className="relative w-full md:w-80 group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-indigo-500 transition-colors" size={16} />
                <input
                  type="text"
                  placeholder="search experts..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-[#161922] border border-white/5 rounded-xl py-3.5 pl-11 pr-4 text-sm focus:outline-none focus:border-indigo-500/50 transition-all placeholder:text-slate-700 shadow-inner"
                />
              </div>
            </div>
          </header>

          <div className="flex items-center gap-2 overflow-x-auto pb-10 scrollbar-hide">
            {filters.map((filter) => (
              <button
                key={filter.id}
                onClick={() => setActiveFilter(filter.id)}
                className={`px-6 py-2.5 rounded-lg text-[11px] font-medium transition-all whitespace-nowrap ${
                    activeFilter === filter.id
                    ? "bg-indigo-600 text-white"
                    : "bg-[#161922] text-slate-500 border border-white/5 hover:border-white/10 hover:text-slate-300"
                }`}
              >
                {filter.label}
              </button>
            ))}
          </div>

          {loading ? (
            <div className="py-24 text-center space-y-4">
                <div className="w-8 h-8 border-2 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin mx-auto" />
                <p className="text-[10px] uppercase tracking-widest text-slate-600 font-bold">loading</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-20">
              <AnimatePresence mode="popLayout">
                {filteredListeners.map((listener) => (
                  <m.div
                    key={listener._id || listener.id}
                    layout
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.98 }}
                    onClick={() => navigate(`/expert/${listener._id || listener.id}`)}
                    className="group relative bg-[#161922] border border-white/5 rounded-2xl p-5 md:p-6 transition-all duration-300 hover:bg-[#1c212e] hover:border-indigo-500/20 cursor-pointer shadow-xl flex flex-col sm:flex-row gap-6"
                  >
                    {/* Avatar Block */}
                    <div className="relative shrink-0 w-24 h-24">
                      <div className="w-full h-full rounded-full overflow-hidden border border-white/5 group-hover:border-indigo-500/30 transition-all duration-500">
                        <img
                          src={listener.profileImage || `https://ui-avatars.com/api/?name=${listener.displayName}&background=6366f1&color=fff`}
                          alt={listener.displayName}
                          className="w-full h-full object-cover grayscale-[0.3] group-hover:grayscale-0 transition-all duration-700 group-hover:scale-105"
                        />
                      </div>
                      <div className={`absolute bottom-1 right-1 w-5 h-5 rounded-full border-2 border-[#161922] shadow-2xl ${listener.isOnline ? 'bg-emerald-500' : 'bg-slate-700'}`}>
                        {listener.isOnline && <div className="w-full h-full rounded-full bg-white animate-pulse opacity-40" />}
                      </div>
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-2">
                        <div className="flex items-center gap-2">
                          <h2 className="text-xl font-medium text-white group-hover:text-indigo-400 transition-colors truncate ">
                            {listener.displayName}
                          </h2>
                          <CheckCircle size={14} className="text-indigo-500" />
                        </div>
                        <div className="flex items-center gap-1.5 bg-white/[0.03] px-2 py-1 rounded-md border border-white/5">
                          <Star size={10} className="text-indigo-400 fill-indigo-400" />
                          <span className="text-[10px] font-bold text-white">{listener.avgRating?.toFixed(1) || "5.0"}</span>
                        </div>
                      </div>

                      <div className="flex items-center gap-3 mb-3">
                         <div className="flex items-center gap-1.5">
                            <Briefcase size={12} className="text-slate-500" />
                            <span className="text-[10px] text-slate-400 font-medium ">{listener.experience || 5}y experience</span>
                         </div>
                         <div className="w-1 h-1 bg-slate-700 rounded-full" />
                         <div className="flex items-center gap-1.5">
                            <Languages size={12} className="text-slate-500" />
                            <span className="text-[10px] text-slate-400 font-medium truncate ">{listener.languages?.slice(0, 2).join(", ") || "english, hindi"}</span>
                         </div>
                      </div>

                      <p className="text-xs text-slate-500 font-light leading-relaxed mb-3 line-clamp-2  opacity-80">
                        {listener.shortBio || "verified professional guide offering consultation and advice."}
                      </p>

                      <div className="flex flex-wrap gap-1.5 mb-5">
                        {(listener.specializations || listener.categories || ['consultant']).slice(0, 3).map(spec => (
                           <span key={spec} className="px-2 py-0.5 rounded bg-indigo-500/10 border border-indigo-500/10 text-[9px] font-medium text-indigo-400 ">
                             {spec}
                           </span>
                        ))}
                      </div>

                      <div className="flex items-center justify-between mt-auto pt-4 border-t border-white/5">
                        <div className="flex items-baseline gap-1">
                          <span className="text-xl font-medium text-white">₹{listener.pricePerMinute}</span>
                          <span className="text-[10px] text-slate-600 font-light ">/min</span>
                        </div>
                        
                        <div className="flex gap-2">
                          <button
                            onClick={(e) => { e.stopPropagation(); openIntake(listener, 'CHAT'); }}
                            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[11px] font-bold transition-all  ${
                              listener.isOnline 
                              ? "bg-white text-black hover:bg-slate-200 shadow-lg" 
                              : "bg-white/5 text-slate-600 cursor-not-allowed border border-white/5"
                            }`}
                          >
                            <MessageSquare size={14} />
                            <span>chat</span>
                          </button>
                          <button
                            onClick={(e) => { e.stopPropagation(); openIntake(listener, 'CALL'); }}
                            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[11px] font-bold transition-all  ${
                              listener.isOnline 
                              ? "bg-white/5 text-white border border-white/10 hover:bg-white/10" 
                              : "bg-white/5 text-slate-600 cursor-not-allowed border border-white/5"
                            }`}
                          >
                            <Phone size={14} />
                            <span>call</span>
                          </button>
                        </div>
                      </div>
                    </div>
                  </m.div>
                ))}
              </AnimatePresence>
            </div>
          )}
        </div>
      </div>
    );
};

export default DilKiBaat;

import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { 
  ArrowLeft, 
  CheckCircle, 
  MessageSquare, 
  Phone, 
  Video, 
  Star, 
  Clock, 
  Languages, 
  ShieldCheck,
  User,
  Activity,
  Calendar,
  Zap
} from "lucide-react";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../context/ToastContext";
import { useCall } from "../context/CallContext";
import IntakeForm from "../components/IntakeForm";

const ExpertDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { token, api, setIsLoginModalOpen } = useAuth();
    const { toast } = useToast();
    const { initiateCall, callActive } = useCall();
    
    const [expert, setExpert] = useState(null);
    const [loading, setLoading] = useState(true);

    // Intake Form State
    const [isIntakeOpen, setIsIntakeOpen] = useState(false);
    const [intakeType, setIntakeType] = useState('CHAT');

    const fetchExpertDetail = async () => {
        try {
            setLoading(true);
            const res = await api.get(`/experts/${id}`);
            setExpert(res.data.data);
        } catch (err) {
            console.error("🌌 [EXPERT_DETAIL_ERROR]", err);
            toast("failed to load expert details", "error");
            navigate("/dil-ki-baat");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchExpertDetail();
    }, [id]);

    const openIntake = (type = 'CHAT') => {
        if (!token) {
            setIsLoginModalOpen(true);
            return;
        }

        // Check if we have saved intake data for THIS expert in this browsing session
        const savedIntake = sessionStorage.getItem(`intake_expert_${id}`);
        if (savedIntake) {
            handleIntakeSubmit(JSON.parse(savedIntake), type);
            return;
        }

        setIntakeType(type);
        setIsIntakeOpen(true);
    };

    const handleIntakeSubmit = async (formData, overrideType) => {
        const finalType = overrideType || intakeType;
        try {
            // Save to session storage so we don't ask again for THIS expert in this browser tab
            sessionStorage.setItem(`intake_expert_${id}`, JSON.stringify(formData));

            const res = await api.post("/chat/start", { 
                expertId: id, 
                type: finalType,
                intakeData: formData
            });
            
            const session = res.data.data.session;
            let url = `/chat/${session.id}`;
            
            if (finalType === 'CALL' || finalType === 'VIDEO') {
                url += `?autoCall=true&type=${finalType === 'VIDEO' ? 'video' : 'voice'}`;
                
                if (!callActive) {
                    const partnerInfo = {
                        name: expert.displayName || "Expert",
                        avatar: expert.profileImage || null
                    };
                    initiateCall(session.id, finalType === 'VIDEO' ? 'video' : 'voice', partnerInfo);
                }
            }
            navigate(url);
        } catch (err) {
            toast(err.response?.data?.message || "expert is busy", "error");
        } finally {
            setIsIntakeOpen(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-[#0d0f17] flex flex-col items-center justify-center gap-6">
                <div className="w-10 h-10 border-[3px] border-white/5 border-t-indigo-600 rounded-full animate-spin"></div>
                <p className="text-slate-500 text-xs font-medium uppercase tracking-widest">loading expert</p>
            </div>
        );
    }

    if (!expert) return null;

    return (
        <div className="min-h-screen bg-[#0d0f17] text-[#e2e8f0]">
            <IntakeForm 
                isOpen={isIntakeOpen}
                onClose={() => setIsIntakeOpen(false)}
                onSubmit={handleIntakeSubmit}
                expert={expert}
            />

            <div className="max-w-7xl mx-auto px-4 md:px-6 pt-24 pb-8 md:pt-36 md:pb-12">
                <button 
                    onClick={() => navigate(-1)}
                    className="flex items-center gap-2 text-slate-500 hover:text-white transition-colors mb-10 group"
                >
                    <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
                    <span className="text-sm font-medium">back</span>
                </button>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* LEFT COLUMN */}
                    <div className="lg:col-span-2 space-y-6">
                        {/* Profile Card */}
                        <div className="bg-[#161922] border border-white/5 rounded-2xl p-6 md:p-8 shadow-xl">
                            <div className="flex flex-col md:flex-row gap-8 items-center md:items-start text-center md:text-left">
                                <div className="relative shrink-0">
                                    <img 
                                        src={expert.profileImage || `https://ui-avatars.com/api/?name=${expert.displayName}&background=6366f1&color=fff`} 
                                        alt={expert.displayName}
