  const fetchWallet = async () => {
    if (!token) return;
    try {
      setLoading(true);
      const res = await api.get("/wallet");
      setWallet(res.data.data);
      if (res.data.data?.balance !== undefined) {
        updateWalletBalance(res.data.data.balance);
