                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, y: -10 }}
                                    className="p-3 bg-rose-500/10 border border-rose-500/20 rounded-xl flex items-center gap-3"
                                >
                                    <AlertCircle size={16} className="text-rose-500 shrink-0" />
