                    </form>
                </div>

                <div className="mt-8 text-center">
                    <p className="text-[10px] text-white/20 uppercase tracking-[0.2em]">Secure Administrative Access Only</p>
                </div>
            </motion.div>
        </div>
    );
};

export default AdminLogin;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  ArrowLeft, 
  ShieldAlert, 
  MessageCircle, 
  ShieldCheck,
  Zap,
  Shield,
  Activity
} from 'lucide-react';
import AdminLayout from '../../components/AdminLayout';
import { useAuth } from '../../context/AuthContext';
import socket from '../../lib/socket';

/**
 * Premium Admin Audit Portal - Intervention Enabled
 * High-fidelity mirrored stream with administrative override capabilities.
 */
const AuditRitual = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { api, user } = useAuth();
  const [messages, setMessages] = useState([]);
  const [session, setSession] = useState(null);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState("");
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const fetchSessionData = async () => {
    try {
      const sessRes = await api.get(`/chat/session/${id}`);
      setSession(sessRes.data.data);

      const msgRes = await api.get(`/chat/messages/${id}`);
      setMessages(msgRes.data.data.messages || []);
    } catch (err) {
      console.error("🌌 [AUDIT_LOAD_ERROR]", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!user?.id) return;

    fetchSessionData();
    socket.emit('join_chat', { sessionId: id, userId: user.id });

    const handleNewMessage = (msg) => {
        if (msg.sessionId === id) {
            setMessages(prev => [...prev, msg]);
        }
    };

    socket.on('new_message', handleNewMessage);
    return () => socket.off('new_message', handleNewMessage);
  }, [id, api, user?.id]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = () => {
    if (!message.trim() || !id || !user?.id) return;

    const messageData = {
      sessionId: id,
      content: message,
      messageType: 'TEXT',
      tempId: Date.now()
    };

    socket.emit('send_message', messageData);
    setMessage("");
  };

  const getPartnerInfo = () => {
    if (!session) return { 
