                        ))}
                    </div>

                    <div className="flex bg-black/40 border border-white/10 rounded-lg px-4 py-2 items-center gap-3 w-full sm:w-64 group focus-within:border-orange-500/50 transition-all">
                        <Search size={14} className="text-white/20 group-focus-within:text-orange-400" />
                        <input 
                            type="text" 
                            placeholder="Search library..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="bg-transparent border-none outline-none text-[10px] font-bold text-white placeholder:text-white/10 w-full" 
                        />
                    </div>
                </div>

                {/* Content Table */}
                <div className="bg-[#121212] border border-white/10 rounded-lg overflow-hidden flex flex-col max-h-[calc(100vh-320px)]">
                    <div className="overflow-x-auto overflow-y-auto custom-scrollbar">
                        <table className="w-full text-left border-collapse min-w-[900px]">
                            <thead className="bg-black/40 border-b border-white/10 text-[10px] uppercase font-bold tracking-wider text-white/40 sticky top-0 z-10 backdrop-blur-md">
                                <tr>
                                    <th className="px-6 py-4 w-12"></th>
                                    <th className="px-6 py-4">Protocol Entry</th>
                                    <th className="px-6 py-4">Attributes</th>
                                    <th className="px-6 py-4">Publish Detail</th>
                                    <th className="px-6 py-4 text-right">Action</th>
                                </tr>
                            </thead>
                            <Reorder.Group 
                                as="tbody" 
                                axis="y" 
                                values={contentItems} 
                                onReorder={handleReorder}
                                className="divide-y divide-white/5"
                            >
                                {loading ? (
                                    <tr>
                                        <td colSpan="5" className="p-20 text-center">
                                            <Loader2 size={32} className="text-orange-500 animate-spin mx-auto mb-4" />
                                            <span className="text-[10px] font-bold tracking-[0.4em] text-white/10 uppercase italic">Retrieving Archives...</span>
                                        </td>
                                    </tr>
                                ) : filteredItems.length === 0 ? (
                                    <tr>
                                        <td colSpan="5" className="p-20 text-center">
                                            <span className="text-[10px] font-bold tracking-[0.4em] text-white/10 uppercase italic">Archives are empty</span>
                                        </td>
                                    </tr>
                                ) : (
                                    filteredItems.map((item) => (
                                        <Reorder.Item 
                                            as="tr" 
                                            key={item.id} 
                                            value={item}
                                            dragListener={activeTab === "HANDBOOK"}
                                            className="hover:bg-white/[0.01] transition-colors group cursor-default active:bg-white/[0.03]"
                                        >
                                            <td className="px-6 py-4">
                                                {activeTab === "HANDBOOK" ? (
                                                    <div className="cursor-grab active:cursor-grabbing text-white/20 hover:text-emerald-500 transition-colors">
                                                        <GripVertical size={16} />
                                                    </div>
                                                ) : (
                                                    <div className="w-4 h-4 rounded-full border border-white/10" />
                                                )}
                                            </td>
                                            <td className="px-6 py-4 max-w-[400px]">
                                                <div className="flex flex-col gap-1.5 text-left">
                                                    <span className={`text-xs font-bold text-white transition-colors truncate ${activeTab === 'HANDBOOK' ? 'group-hover:text-emerald-400' : 'group-hover:text-orange-400'}`}>{item.title || "Untitled Guidance"}</span>
                                                    <p className="text-[10px] text-white/40 line-clamp-2 leading-relaxed italic">"{item.content}"</p>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex flex-col gap-1 text-left">
                                                    <div className="flex items-center gap-2 text-[10px] text-white/30 font-bold uppercase tracking-tight">
                                                        <User size={10} className={activeTab === 'HANDBOOK' ? 'text-emerald-500/50' : 'text-orange-500/50'} />
                                                        <span>{item.author || "Cosmic Bot"}</span>
                                                    </div>
                                                    {item.mediaUrl && (
                                                        <a href={item.mediaUrl} target="_blank" className="flex items-center gap-1.5 text-[9px] text-blue-400 hover:text-blue-300 transition-colors uppercase tracking-widest font-bold">
                                                            <ExternalLink size={10} /> View Media
                                                        </a>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex flex-col gap-1 text-left">
                                                    <div className="flex items-center gap-2 text-[10px] text-white/40 font-bold">
                                                        <Calendar size={10} />
                                                        <span>{new Date(item.publishDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' })}</span>
                                                    </div>
                                                    <span className="text-[8px] text-white/20 uppercase tracking-[0.2em]">Stellar Schedule</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <div className="flex items-center justify-end gap-2">
                                                    <button 
                                                        onClick={() => handleToggleActive(item)}
                                                        className={`relative inline-flex h-4 w-8 items-center rounded-full transition-colors focus:outline-none ${
                                                            item.isActive ? (activeTab === 'HANDBOOK' ? 'bg-emerald-600' : 'bg-orange-600') : 'bg-white/10'
                                                        }`}
                                                    >
                                                        <span
                                                            className={`inline-block h-2.5 w-2.5 transform rounded-full bg-white transition-transform ${
                                                                item.isActive ? 'translate-x-4.5' : 'translate-x-0.5'
                                                            }`}
                                                        />
                                                    </button>
                                                    <button 
                                                        onClick={() => handleOpenEdit(item)}
                                                        className="p-2 bg-white/5 border border-white/10 rounded-lg text-white/40 hover:text-white transition-all"
                                                    >
                                                        <Edit size={12} />
                                                    </button>
                                                    <button 
                                                        onClick={() => handleDelete(item.id)}
                                                        className="p-2 bg-white/5 border border-white/10 rounded-lg text-red-500/40 hover:text-red-500 transition-all hover:bg-red-500/10"
                                                    >
                                                        <Trash2 size={12} />
                                                    </button>
                                                </div>
                                            </td>
                                        </Reorder.Item>
                                    ))
                                )}
                            </Reorder.Group>
                        </table>
                    </div>
                </div>

                <p className="text-center text-[9px] font-sans font-semibold tracking-[0.5em] text-white/5 italic">
                    Universal Broadcast Layer • Guidance Distribution Active
                </p>
            </div>

            {/* Add Content Modal */}
            <AnimatePresence>
                {isAdding && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                        <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setIsAdding(false)}
                            className="absolute inset-0 bg-black/80 backdrop-blur-md"
                        />
                        <motion.div 
                            initial={{ opacity: 0, scale: 0.9, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.9, y: 20 }}
                            className="relative w-full max-w-lg bg-[#121212] border border-white/10 rounded-2xl shadow-2xl overflow-hidden"
                        >
                             <div className="p-6 border-b border-white/5 flex items-center justify-between">
                                 <div className="flex items-center gap-3">
                                     <div className="w-8 h-8 rounded-lg bg-orange-600/10 border border-orange-500/20 flex items-center justify-center text-orange-400">
                                          {editingItem ? <Edit size={16} /> : <Plus size={16} />}
                                      </div>
                                      <h3 className="text-sm font-bold text-white uppercase tracking-widest">{editingItem ? "Update Entry" : "Add New Content"}</h3>
                                  </div>
                                 <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-white/5 rounded-full transition-colors text-white/40 hover:text-white">
                                     <X size={20} />
                                 </button>
                             </div>

                             <form onSubmit={handleSubmit} className="p-6 space-y-5">
                                {form.type !== "HANDBOOK" ? (
                                    <>
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-1.5">
                                                <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Category</label>
                                                <select 
                                                    value={form.type}
                                                    onChange={(e) => setForm({...form, type: e.target.value})}
                                                    className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-bold text-white outline-none focus:border-orange-500/50 transition-all"
                                                >
                                                    <option value="MESSAGE">Daily Guidance</option>
                                                    <option value="MEDIA">Media Library</option>
                                                    <option value="BLOG">Knowledge Hub</option>
                                                </select>
                                            </div>
                                            <div className="space-y-1.5">
                                                <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Publish Date</label>
                                                <input 
                                                    type="date"
                                                    value={form.publishDate}
                                                    onChange={(e) => setForm({...form, publishDate: e.target.value})}
                                                    className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-bold text-white outline-none focus:border-orange-500/50 transition-all"
                                                />
                                            </div>
                                        </div>

                                        <div className="space-y-1.5">
                                            <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Library Title</label>
                                            <input 
                                                type="text"
                                                placeholder="Enter title..."
                                                value={form.title}
                                                onChange={(e) => setForm({...form, title: e.target.value})}
                                                className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-bold text-white outline-none focus:border-orange-500/50 transition-all"
                                                required
                                            />
                                        </div>

                                        <div className="space-y-1.5">
                                            <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Description</label>
                                            <textarea 
                                                rows="4"
                                                value={form.content}
                                                onChange={(e) => setForm({...form, content: e.target.value})}
                                                className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-bold text-white outline-none focus:border-orange-500/50 transition-all resize-none"
                                                required
                                            />
                                        </div>

                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-1.5">
                                                <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Author</label>
                                                <input 
                                                    type="text"
                                                    value={form.author}
                                                    onChange={(e) => setForm({...form, author: e.target.value})}
                                                    className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-bold text-white outline-none focus:border-orange-500/50 transition-all"
                                                />
                                            </div>
                                            <div className="space-y-1.5">
                                                <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Media URL</label>
                                                <input 
                                                    type="url"
                                                    value={form.mediaUrl}
                                                    onChange={(e) => setForm({...form, mediaUrl: e.target.value})}
                                                    className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-bold text-white outline-none focus:border-orange-500/50 transition-all"
                                                />
                                            </div>
                                        </div>
                                    </>
                                ) : (
                                    <>
                                        {/* Specialized Handbook Form */}
                                        <div className="p-4 bg-emerald-500/5 border border-emerald-500/10 rounded-xl mb-4">
                                            <p className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest flex items-center gap-2">
                                                <Book size={12} /> Expert Manual Protocol
                                            </p>
                                        </div>

                                        <div className="space-y-1.5">
                                            <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Section Title</label>
                                            <input 
                                                type="text"
                                                placeholder="e.g., Communication Guidelines"
                                                value={form.title}
                                                onChange={(e) => setForm({...form, title: e.target.value})}
                                                className="w-full bg-black/40 border border-white/10 rounded-lg px-6 py-3 text-sm font-bold text-white outline-none focus:border-emerald-500/50 transition-all"
                                                required
                                            />
                                        </div>

                                        <div className="space-y-1.5">
                                            <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest pl-1">Protocol Description (Paragraph Content)</label>
                                            <textarea 
                                                rows="6"
                                                placeholder="Draft the official guidance here..."
                                                value={form.content}
                                                onChange={(e) => setForm({...form, content: e.target.value})}
                                                className="w-full bg-black/40 border border-white/10 rounded-lg px-6 py-4 text-sm font-medium text-white/70 outline-none focus:border-emerald-500/50 transition-all resize-none leading-relaxed"
                                                required
                                            />
                                        </div>
                                    </>
                                )}

                                <div className="flex items-center gap-3 py-2">
                                    <input 
                                        type="checkbox"
                                        id="isActive"
                                        checked={form.isActive}
                                        onChange={(e) => setForm({...form, isActive: e.target.checked})}
                                        className={`w-4 h-4 rounded border-white/10 bg-black/40 focus:ring-offset-0 ${form.type === 'HANDBOOK' ? 'text-emerald-600 focus:ring-emerald-600' : 'text-orange-600 focus:ring-orange-600'}`}
                                    />
                                    <label htmlFor="isActive" className="text-[10px] font-bold text-white/40 uppercase tracking-widest cursor-pointer">Live in Expert Panel</label>
                                </div>

                                <button 
                                    type="submit"
                                    disabled={submitting}
                                    className={`w-full py-4 disabled:opacity-50 text-white rounded-xl text-[10px] font-bold uppercase tracking-[0.2em] transition-all shadow-xl flex items-center justify-center gap-3 mt-4 ${
                                        form.type === 'HANDBOOK' 
                                        ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/30' 
                                        : 'bg-orange-600 hover:bg-orange-500 shadow-orange-900/30'
                                    }`}
                                >
                                    {submitting ? (
                                        <Loader2 size={16} className="animate-spin" />
                                    ) : (
                                        <>{editingItem ? "Sync Manual Entry" : "Establish Protocol"} <CheckCircle size={16} /></>
                                    )}
                                </button>
                            </form>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </AdminLayout>
    );
};

export default AdminContent;

import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { Users, ShieldCheck, HeartPulse, IndianRupee, Loader2, Wallet } from "lucide-react";
import AdminLayout from "../../components/AdminLayout";
import { useAuth } from "../../context/AuthContext";

/**
 * Admin Overview Dashboard
 */
const AdminOverview = () => {
    const { api } = useAuth();
    const navigate = useNavigate();
    const [stats, setStats] = useState([
        { label: "Active Users", value: "...", icon: Users, color: "text-blue-400", border: "border-blue-500/10", key: "totalUsers" },
        { label: "Active Experts", value: "...", icon: ShieldCheck, color: "text-purple-400", border: "border-purple-500/10", key: "activeExperts" },
        { label: "Total Revenue", value: "...", icon: IndianRupee, color: "text-emerald-400", border: "border-emerald-500/10", key: "revenue" },
        { label: "Live Sessions", value: "...", icon: HeartPulse, color: "text-rose-400", border: "border-rose-500/10", key: "liveChats" }
    ]);
    const [pendingExperts, setPendingExperts] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchDashboardData = async () => {
        try {
            const [overviewRes, pendingRes] = await Promise.all([
                api.get("/admin/overview"),
                api.get("/admin/experts/pending")
            ]);

            const data = overviewRes.data.data;
            const pending = pendingRes.data.data;

            setStats(prev => prev.map(s => ({
                ...s,
                value: s.key === 'revenue' ? `₹${data[s.key] || 0}` : (data[s.key] || 0).toString()
            })));

            setPendingExperts(pending.slice(0, 5)); 
        } catch (err) {
            console.error("[ADMIN_OVERVIEW_ERROR]", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchDashboardData();
        const interval = setInterval(fetchDashboardData, 15000);
        return () => clearInterval(interval);
    }, [api]);

    const quickLinks = [
        { label: "User Directory", path: "/admin/users", icon: Users, color: "text-blue-400" },
        { label: "Verifications", path: "/admin/verifications", icon: ShieldCheck, color: "text-purple-400" },
        { label: "Finances", path: "/admin/finances", icon: IndianRupee, color: "text-emerald-400" },
        { label: "Payouts", path: "/admin/payouts", icon: Wallet, color: "text-amber-400" },
    ];

    return (
        <AdminLayout>
            <div className="space-y-6 text-left">

                {/* Stats Grid */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 text-left">
                    {stats.map((stat, idx) => (
                        <motion.div 
                            key={stat.label}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: idx * 0.08 }}
                            className={`p-5 bg-[#121212] border border-white/10 rounded-lg flex flex-col gap-3 group hover:border-white/20 transition-all text-left`}
                        >
                            <div className="flex items-center justify-between">
                                <div className={`w-9 h-9 rounded-lg bg-white/5 border border-white/5 flex items-center justify-center ${stat.color}`}>
                                    <stat.icon size={16} />
                                </div>
                            </div>
                            <div className="space-y-1 text-left">
                                <span className="text-[9px] font-sans font-semibold tracking-widest text-white/50 uppercase">{stat.label}</span>
                                <div className="text-2xl font-bold tracking-tight text-white">
                                    {loading ? <div className="w-16 h-7 bg-white/5 animate-pulse rounded"></div> : stat.value}
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>

                {/* Main Grid: Pending Experts + Quick Links */}
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

                    {/* Pending Expert Verifications */}
                    <div className="lg:col-span-8 space-y-4">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3 text-white/85">
                                <ShieldCheck size={18} className="text-purple-400" />
                                <h2 className="text-[10px] font-sans font-bold tracking-[0.2em] uppercase">Pending Verifications</h2>
                            </div>
                            <button 
                                onClick={() => navigate('/admin/verifications')}
                                className="text-[10px] font-bold text-purple-400 hover:text-white tracking-wider uppercase transition-colors"
                            >
                                View All →
                            </button>
                        </div>

                        <div className="bg-[#121212] border border-white/10 rounded-lg overflow-hidden">
                            {loading ? (
                                <div className="p-16 text-center flex flex-col items-center justify-center gap-4">
                                    <Loader2 size={28} className="text-purple-500 animate-spin" />
                                    <span className="text-[10px] font-sans font-semibold tracking-[0.4em] text-white/40 uppercase italic">Loading...</span>
                                </div>
                            ) : pendingExperts.length === 0 ? (
                                <div className="p-16 text-center text-[10px] font-sans font-semibold tracking-[0.4em] text-white/20 uppercase italic">
                                    No pending verifications
                                </div>
                            ) : (
                                <div className="divide-y divide-white/5">
                                    {pendingExperts.map((expert) => (
                                        <div key={expert.id} className="px-6 py-4 flex items-center justify-between hover:bg-white/[0.02] transition-colors group">
                                            <div className="flex items-center gap-4">
                                                <div className="w-10 h-10 rounded-lg bg-white/5 border border-white/5 overflow-hidden shrink-0">
                                                    <img 
                                                        src={expert.user?.avatar || `https://ui-avatars.com/api/?name=${expert.user?.name || 'E'}&background=6D28D9&color=FFFFFF`} 
                                                        className="w-full h-full object-cover" 
                                                        alt="" 
                                                    />
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-bold text-white/90">{expert.user?.name || expert.displayName || "Expert"}</span>
                                                    <span className="text-[10px] text-white/40">{expert.user?.phone || "No phone"}</span>
                                                    <span className="text-[10px] text-white/30">{expert.specialization || "Specialist"} • {expert.documents?.length || 0} docs</span>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-3">
                                                <span className="hidden md:block px-2 py-0.5 rounded text-[9px] uppercase font-bold tracking-wider bg-amber-500/10 text-amber-400 border border-amber-500/20">
                                                    Pending
                                                </span>
                                                <button 
                                                    onClick={() => navigate('/admin/verifications')}
                                                    className="px-4 py-2 bg-purple-600/10 hover:bg-purple-600/20 border border-purple-500/20 text-purple-400 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all"
                                                >
                                                    Review
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Quick Navigation */}
                    <div className="lg:col-span-4 space-y-4">
                        <div className="flex items-center gap-3 text-white/85">
                            <HeartPulse size={18} className="text-emerald-400" />
                            <h2 className="text-[10px] font-sans font-bold tracking-[0.2em] uppercase">Quick Access</h2>
                        </div>

                        <div className="bg-[#121212] border border-white/10 rounded-lg divide-y divide-white/5">
                            {quickLinks.map((link) => (
                                <button
                                    key={link.path}
                                    onClick={() => navigate(link.path)}
                                    className="w-full px-5 py-4 flex items-center gap-4 hover:bg-white/[0.03] transition-colors text-left group"
                                >
                                    <div className={`w-8 h-8 rounded-lg bg-white/5 border border-white/5 flex items-center justify-center ${link.color} group-hover:scale-110 transition-transform`}>
                                        <link.icon size={14} />
                                    </div>
                                    <span className="text-xs font-bold text-white/70 group-hover:text-white transition-colors tracking-wider uppercase">{link.label}</span>
                                    <span className="ml-auto text-white/20 group-hover:text-white/50 transition-colors text-sm">→</span>
                                </button>
                            ))}
                        </div>

                        {/* Platform Status */}
                        <div className="bg-[#121212] border border-white/10 rounded-lg p-5 space-y-3">
                            <div className="flex items-center gap-2">
                                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                                <span className="text-[10px] font-bold text-white/50 uppercase tracking-wider">Platform Status</span>
                            </div>
                            <p className="text-[10px] text-white/30 leading-relaxed">
                                All systems operational. Sessions are end-to-end encrypted.
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </AdminLayout>
    );
};

export default AdminOverview;

import React, { useState, useEffect } from "react";
import { Wallet, Loader2, CheckCircle, Clock, Ban } from "lucide-react";
import AdminLayout from "../../components/AdminLayout";
import { useAuth } from "../../context/AuthContext";
import { useToast } from "../../context/ToastContext";
import { motion, AnimatePresence } from "framer-motion";

/**
 * Admin Payout Approvals — Expert Withdrawal Management
 */
const AdminPayouts = () => {
    const { api } = useAuth();
    const { toast } = useToast();
    const [payouts, setPayouts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState("ALL");
    const [confirmModal, setConfirmModal] = useState({ isOpen: false, payout: null });
    const [submitting, setSubmitting] = useState(false);

    const fetchPayouts = async () => {
        try {
            setLoading(true);
            const res = await api.get("/admin/payouts");
            setPayouts(res.data.data);
        } catch (err) {
            console.error("[PAYOUT_FETCH_ERROR]", err);
            toast("Failed to fetch payouts", "error");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchPayouts();
    }, [api]);

    const executeApprovePayout = async () => {
        if (!confirmModal.payout) return;
        try {
            setSubmitting(true);
            await api.patch(`/admin/payouts/${confirmModal.payout.id}/approve`);
            toast("Payout approved successfully", "success");
            setConfirmModal({ isOpen: false, payout: null });
            fetchPayouts();
        } catch (err) {
            console.error("[PAYOUT_APPROVE_ERROR]", err);
            toast(err.response?.data?.message || "Failed to approve payout", "error");
        } finally {
            setSubmitting(false);
        }
    };

    const filteredPayouts = filter === "ALL" 
        ? payouts 
        : payouts.filter(p => p.status === filter);

    const pendingCount = payouts.filter(p => p.status === 'PENDING').length;
    const completedCount = payouts.filter(p => p.status === 'COMPLETED').length;
    const totalPending = payouts.filter(p => p.status === 'PENDING').reduce((sum, p) => sum + p.amount, 0);
    const totalCompleted = payouts.filter(p => p.status === 'COMPLETED').reduce((sum, p) => sum + p.amount, 0);

    const filters = ["ALL", "PENDING", "COMPLETED"];

    return (
        <AdminLayout>
            <div className="space-y-6 text-left relative">

                <div className="flex flex-col xl:flex-row items-start xl:items-center justify-between gap-6 group text-left">
                    <div className="flex items-center gap-4 text-white/85 group-hover:text-white transition-colors text-left">
                        <Wallet size={20} className="text-amber-400 shadow-[0_0_10px_rgba(245,158,11,0.2)]" />
                        <h2 className="text-[10px] font-sans font-bold tracking-[0.2em] uppercase">Payout Approvals</h2>
                    </div>
                </div>

                {/* Stats Cards */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-left">
                    <div className="p-4 bg-white/[0.02] border border-white/5 rounded-lg flex flex-col gap-2 group hover:bg-white/5 transition-all text-left">
                        <span className="text-[9px] font-sans font-semibold tracking-widest text-white/50 uppercase">Total Requests</span>
                        <div className="text-xl font-semibold tracking-tight">{payouts.length}</div>
                    </div>
                    <div className="p-4 bg-amber-500/[0.02] border border-amber-500/10 rounded-lg flex flex-col gap-2 group hover:bg-amber-500/5 transition-all text-left">
                        <span className="text-[9px] font-sans font-semibold tracking-widest text-amber-400/60 uppercase">Pending</span>
                        <div className="text-xl font-semibold tracking-tight text-amber-400">{pendingCount}</div>
                    </div>
                    <div className="p-4 bg-emerald-500/[0.02] border border-emerald-500/10 rounded-lg flex flex-col gap-2 group hover:bg-emerald-500/5 transition-all text-left">
                        <span className="text-[9px] font-sans font-semibold tracking-widest text-emerald-400/60 uppercase">Approved</span>
                        <div className="text-xl font-semibold tracking-tight text-emerald-400">{completedCount}</div>
                    </div>
                    <div className="p-4 bg-white/[0.02] border border-white/5 rounded-lg flex flex-col gap-2 group hover:bg-white/5 transition-all text-left">
                        <span className="text-[9px] font-sans font-semibold tracking-widest text-white/50 uppercase">Pending Volume</span>
                        <div className="text-xl font-semibold tracking-tight text-amber-400">₹{totalPending}</div>
                    </div>
                </div>

                {/* Filter Tabs */}
                <div className="flex items-center gap-2">
                    {filters.map(f => (
                        <button
                            key={f}
                            onClick={() => setFilter(f)}
                            className={`px-4 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all border ${
                                filter === f
                                ? 'bg-white/10 text-white border-white/20'
                                : 'bg-transparent text-white/40 border-white/5 hover:text-white/70 hover:border-white/10'
                            }`}
                        >
                            {f}
                            {f === 'PENDING' && pendingCount > 0 && (
                                <span className="ml-2 w-4 h-4 inline-flex items-center justify-center rounded-full bg-rose-500 text-white text-[9px]">
                                    {pendingCount}
                                </span>
                            )}
                        </button>
                    ))}
                </div>

                {/* Desktop Table */}
                <div className="hidden md:block w-full overflow-hidden bg-[#121212] border border-white/10 rounded-lg shadow-2xl">
                    <div className="max-h-[60vh] overflow-y-auto overflow-x-auto scrollbar-hide">
                        <table className="w-full text-sm text-left font-sans">
                            <thead className="sticky top-0 z-10 bg-[#121212] border-b border-white/10 text-white/50 font-bold uppercase tracking-wider text-[11px]">
                                <tr>
                                    <th className="px-6 py-4">Expert</th>
                                    <th className="px-6 py-4">Bank Details</th>
                                    <th className="px-6 py-4">Amount</th>
                                    <th className="px-6 py-4">Status</th>
                                    <th className="px-6 py-4">Requested</th>
                                    <th className="px-6 py-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {loading ? (
                                    <tr>
                                        <td colSpan="6" className="p-20 text-center">
                                            <div className="flex flex-col items-center justify-center gap-4">
                                                <Loader2 size={32} className="text-amber-500 animate-spin" />
                                                <span className="text-[10px] font-sans font-semibold tracking-[0.5em] text-white/40 uppercase italic">
                                                    Loading Payouts...
                                                </span>
                                            </div>
                                        </td>
                                    </tr>
                                ) : filteredPayouts.length === 0 ? (
                                    <tr>
                                        <td colSpan="6" className="p-20 text-center text-[10px] font-sans font-semibold tracking-[0.5em] text-white/20 uppercase italic">
                                            No payout requests found
                                        </td>
                                    </tr>
                                ) : filteredPayouts.map((p) => (
                                    <tr key={p.id} className="hover:bg-white/[0.02] transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col">
                                                <div className="font-bold text-white/90">{p.expert?.user?.name || p.expert?.displayName || "Expert"}</div>
                                                <div className="text-[11px] text-white/40">{p.expert?.user?.phone}</div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col gap-0.5">
                                                {p.expert?.upiId && (
                                                    <div className="text-[11px] text-white/70"><span className="text-white/30">UPI:</span> {p.expert.upiId}</div>
                                                )}
                                                {p.expert?.bankName && (
                                                    <div className="text-[11px] text-white/70"><span className="text-white/30">Bank:</span> {p.expert.bankName}</div>
                                                )}
                                                {p.expert?.accountNumber && (
                                                    <div className="text-[11px] text-white/70"><span className="text-white/30">A/C:</span> {p.expert.accountNumber}</div>
                                                )}
                                                {p.expert?.ifscCode && (
                                                    <div className="text-[11px] text-white/70"><span className="text-white/30">IFSC:</span> {p.expert.ifscCode}</div>
                                                )}
                                                {!p.expert?.upiId && !p.expert?.bankName && (
                                                    <span className="text-[10px] text-white/20 italic">Not provided</span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="font-bold text-lg text-emerald-400">₹{p.amount}</span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider ${
                                                p.status === 'COMPLETED' 
                                                ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' 
                                                : p.status === 'FAILED'
                                                ? 'bg-rose-500/10 text-rose-400 border border-rose-500/20'
                                                : 'bg-amber-500/10 text-amber-400 border border-amber-500/20'
                                            }`}>
                                                {p.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="text-xs text-white/50 italic">
                                                {new Date(p.createdAt).toLocaleDateString()}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {p.status === 'PENDING' ? (
                                                <button 
                                                    onClick={() => setConfirmModal({ isOpen: true, payout: p })}
                                                    className="px-4 py-2 bg-emerald-600/10 hover:bg-emerald-600/20 border border-emerald-500/20 text-emerald-400 rounded-lg text-xs font-bold uppercase tracking-wider transition-all"
                                                >
                                                    Approve
                                                </button>
                                            ) : (
                                                <div className="inline-flex items-center gap-2 text-emerald-500 text-xs font-bold uppercase px-4 py-2 opacity-50">
                                                    <CheckCircle size={14} /> Done
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* Mobile Card Stack */}
                <div className="md:hidden max-h-[70vh] overflow-y-auto scrollbar-hide space-y-4 text-left p-1 pb-10">
                    {loading ? (
                        <div className="p-20 text-center flex flex-col items-center justify-center gap-4">
                            <Loader2 size={28} className="text-amber-500 animate-spin" />
                            <span className="text-[10px] font-sans font-semibold tracking-[0.4em] text-white/40 uppercase italic">Loading...</span>
                        </div>
                    ) : filteredPayouts.length === 0 ? (
                        <div className="p-20 text-center text-[10px] font-sans font-semibold tracking-[0.4em] text-white/20 uppercase italic">No payout requests</div>
                    ) : filteredPayouts.map((p) => (
                        <div key={p.id} className="p-5 bg-white/[0.02] border border-white/5 rounded-2xl space-y-4 group active:scale-[0.98] transition-all text-left backdrop-blur-3xl shadow-xl">
                            <div className="flex items-center justify-between text-left">
                                <div className="flex flex-col text-left">
                                    <span className="text-sm font-bold text-white/90">{p.expert?.user?.name || "Expert"}</span>
                                    <span className="text-[10px] font-sans font-semibold text-white/40 tracking-widest italic">{p.expert?.user?.phone}</span>
                                </div>
                                <span className={`px-3 py-1 rounded-full text-[9px] font-sans font-bold tracking-widest border shadow-lg ${
                                    p.status === 'COMPLETED' ? 'border-emerald-500/30 bg-emerald-500/10 text-emerald-400' :
                                    p.status === 'FAILED' ? 'border-rose-500/30 bg-rose-500/10 text-rose-400' :
                                    'border-amber-500/30 bg-amber-500/10 text-amber-400'
                                }`}>
                                    {p.status}
                                </span>
                            </div>

                            <div className="grid grid-cols-2 gap-4 pt-4 border-t border-white/5">
                                <div className="flex flex-col gap-1 text-left">
                                    <span className="text-[8px] font-sans font-semibold text-white/30 tracking-[0.2em] uppercase">Amount</span>
                                    <span className="text-lg font-bold text-emerald-400">₹{p.amount}</span>
                                </div>
                                <div className="flex flex-col gap-1 text-right">
                                    <span className="text-[8px] font-sans font-semibold text-white/30 tracking-[0.2em] uppercase">Date</span>
                                    <span className="text-[10px] font-sans font-semibold text-white/60 italic">
                                        {new Date(p.createdAt).toLocaleDateString()}
                                    </span>
                                </div>
                            </div>

                            {/* Bank Details */}
                            <div className="pt-4 border-t border-white/5 space-y-1">
                                <span className="text-[8px] font-sans font-semibold text-white/30 tracking-[0.2em] uppercase">Bank Details</span>
                                <div className="space-y-0.5">
                                    {p.expert?.upiId && <div className="text-[11px] text-white/70"><span className="text-white/30">UPI:</span> {p.expert.upiId}</div>}
                                    {p.expert?.bankName && <div className="text-[11px] text-white/70"><span className="text-white/30">Bank:</span> {p.expert.bankName}</div>}
                                    {p.expert?.accountNumber && <div className="text-[11px] text-white/70"><span className="text-white/30">A/C:</span> {p.expert.accountNumber}</div>}
                                    {p.expert?.ifscCode && <div className="text-[11px] text-white/70"><span className="text-white/30">IFSC:</span> {p.expert.ifscCode}</div>}
                                    {!p.expert?.upiId && !p.expert?.bankName && <span className="text-[10px] text-white/20 italic">Not provided</span>}
                                </div>
                            </div>

                            {p.status === 'PENDING' && (
                                <div className="flex items-center gap-3 pt-4 border-t border-white/5">
                                    <button
                                        onClick={() => setConfirmModal({ isOpen: true, payout: p })}
                                        className="flex-1 py-3 bg-emerald-600/5 hover:bg-emerald-600/10 border border-emerald-500/10 rounded-xl flex items-center justify-center text-emerald-500 transition-all"
                                    >
                                        <CheckCircle size={18} />
                                        <span className="ml-2 text-xs font-semibold">Approve</span>
                                    </button>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Confirmation Modal */}
                <AnimatePresence>
                    {confirmModal.isOpen && confirmModal.payout && (
                        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/80 backdrop-blur-sm">
                            <motion.div 
                                initial={{ opacity: 0, scale: 0.95, y: 20 }}
                                animate={{ opacity: 1, scale: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95, y: 20 }}
                                className="bg-[#121212] border border-white/10 rounded-3xl w-full max-w-md overflow-hidden shadow-2xl relative"
                            >
                                <div className="p-6 text-center space-y-6">
                                    <div className="w-16 h-16 mx-auto rounded-2xl bg-emerald-500/10 text-emerald-500 flex items-center justify-center">
                                        <Wallet size={32} />
                                    </div>

                                    <div className="space-y-2">
                                        <h3 className="text-xl font-bold text-white">Approve Payout?</h3>
                                        <p className="text-sm text-white/50">
                                            Approve <strong className="text-white">₹{confirmModal.payout.amount}</strong> payout to{" "}
                                            <strong className="text-white">{confirmModal.payout.expert?.user?.name || "Expert"}</strong>?
                                            This action marks the payout as completed.
                                        </p>
                                    </div>

                                    <div className="flex items-center gap-3 pt-4">
                                        <button 
                                            onClick={() => setConfirmModal({ isOpen: false, payout: null })}
                                            className="flex-1 py-3 rounded-xl bg-white/5 hover:bg-white/10 text-white font-bold text-sm transition-all"
                                            disabled={submitting}
                                        >
                                            Cancel
                                        </button>
                                        <button 
                                            onClick={executeApprovePayout}
                                            disabled={submitting}
                                            className="flex-1 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-500 text-white font-bold text-sm transition-all flex items-center justify-center gap-2"
                                        >
                                            {submitting ? <Loader2 size={16} className="animate-spin" /> : "Yes, Approve"}
                                        </button>
                                    </div>
                                </div>
                            </motion.div>
                        </div>
                    )}
                </AnimatePresence>
            </div>
        </AdminLayout>
    );
};

export default AdminPayouts;

import React, { useState, useEffect } from "react";
import { 
    MessageCircle, 
    Clock, 
    ArrowRight, 
    Search,
    Shield,
    Loader2,
    Users,
    Zap,
    ExternalLink
} from "lucide-react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import { useToast } from "../../context/ToastContext";
import AdminLayout from "../../components/AdminLayout";
import socket from "../../lib/socket";

/**
 * Admin Ritual Monitor - Real-time Oversight
 */
const RitualMonitor = () => {
    const { api, token } = useAuth();
    const navigate = useNavigate();
    const { toast } = useToast();
    const [sessions, setSessions] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");
    const [filter, setFilter] = useState("ALL");

    const fetchAllSessions = async () => {
        try {
            const res = await api.get("/admin/sessions/live");
            const sessionData = Array.isArray(res.data?.data) ? res.data.data : (res.data?.data?.sessions || []);
            setSessions(sessionData);
        } catch (err) {
            console.error("[MONITOR_SYNC_ERROR]", err);
            toast("Failed to sync live streams", "error");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (!token) return;
        fetchAllSessions();

        const refreshData = () => fetchAllSessions();
        socket.on("session_started", refreshData);
        socket.on("session_ended", refreshData);
        socket.on("new_ritual_request", refreshData);

        const interval = setInterval(fetchAllSessions, 15000);
        return () => {
            socket.off("session_started", refreshData);
            socket.off("session_ended", refreshData);
            socket.off("new_ritual_request", refreshData);
            clearInterval(interval);
        };
    }, [api, token]);

    const filteredSessions = Array.isArray(sessions) ? sessions.filter(s => {
        const nameMatch = 
            (s.user?.name || "").toLowerCase().includes(searchTerm.toLowerCase()) || 
            (s.expert?.displayName || "").toLowerCase().includes(searchTerm.toLowerCase());

        const statusMatch = filter === "ALL" || s.status === filter;
        return nameMatch && statusMatch;
    }) : [];

    const stats = [
        { label: "Live Sessions", value: sessions.filter(s => s.status === 'ACTIVE').length, icon: Zap, color: "text-emerald-400" },
        { label: "Waiting Users", value: sessions.filter(s => s.status === 'WAITING').length, icon: Clock, color: "text-amber-400" },
        { label: "Total Monitored", value: sessions.length, icon: Shield, color: "text-purple-400" }
    ];

    return (
        <AdminLayout>
            <div className="space-y-6 text-left">
                {/* Header & Stats Bundle */}
                <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
                    <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-lg bg-purple-600/10 border border-purple-500/20 flex items-center justify-center text-purple-400">
                             <MessageCircle size={20} />
                        </div>
                        <div className="text-left">
                             <h2 className="text-[10px] font-sans font-bold tracking-[0.2em] text-white/50 uppercase">Security Matrix</h2>
                             <h1 className="text-xl font-bold text-white">Ritual <span className="text-purple-400">Monitor</span></h1>
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        {stats.map((s, i) => (
                            <div key={i} className="px-4 py-2 bg-[#121212] border border-white/5 rounded-lg flex items-center gap-3">
                                <s.icon size={14} className={s.color} />
                                <div className="flex flex-col">
                                    <span className="text-[8px] font-bold text-white/30 uppercase tracking-widest">{s.label}</span>
                                    <span className="text-sm font-bold text-white">{s.value}</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Filters Row */}
                <div className="flex flex-col sm:flex-row items-center justify-between gap-4 p-4 bg-[#121212] border border-white/10 rounded-lg">
                    <div className="flex bg-black/40 border border-white/10 rounded-lg px-4 py-2.5 items-center gap-3 w-full sm:w-80 group focus-within:border-purple-500/50 transition-all">
                        <Search size={16} className="text-white/20 group-focus-within:text-purple-400" />
                        <input 
                            type="text" 
                            placeholder="Search by User or Expert..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="bg-transparent border-none outline-none text-xs font-bold text-white placeholder:text-white/10 w-full" 
                        />
                    </div>

                    <div className="flex p-1 bg-black/40 border border-white/10 rounded-lg">
                        {["ALL", "ACTIVE", "WAITING"].map((f) => (
                            <button
                                key={f}
                                onClick={() => setFilter(f)}
                                className={`px-4 py-1.5 rounded-md text-[9px] font-bold tracking-widest transition-all ${
                                    filter === f 
                                    ? "bg-purple-600 text-white shadow-lg" 
                                    : "text-white/30 hover:text-white/60"
                                }`}
                            >
                                {f}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Main Table Content - Now Scrollable */}
                <div className="bg-[#121212] border border-white/10 rounded-lg overflow-hidden flex flex-col max-h-[calc(100vh-320px)]">
                    <div className="overflow-x-auto overflow-y-auto custom-scrollbar">
                        <table className="w-full text-left border-collapse min-w-[800px]">
                            <thead className="bg-black/40 border-b border-white/10 text-[10px] uppercase font-bold tracking-wider text-white/40 sticky top-0 z-20 backdrop-blur-md">
                                <tr>
                                    <th className="px-6 py-4">User</th>
                                    <th className="px-6 py-4">Expert / Stage</th>
                                    <th className="px-6 py-4">Details</th>
                                    <th className="px-6 py-4">Status</th>
                                    <th className="px-6 py-4 text-right">Action</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                            {loading ? (
                                <tr>
                                    <td colSpan="5" className="p-20 text-center">
                                        <div className="flex flex-col items-center gap-3">
                                            <Loader2 size={32} className="text-purple-500 animate-spin" />
                                            <span className="text-[10px] font-bold tracking-[0.4em] text-white/20 uppercase italic">Syncing Streams...</span>
                                        </div>
                                    </td>
                                </tr>
                            ) : filteredSessions.length === 0 ? (
                                <tr>
                                    <td colSpan="5" className="p-20 text-center">
                                        <span className="text-[10px] font-bold tracking-[0.4em] text-white/20 uppercase italic">No active rituals found</span>
                                    </td>
                                </tr>
                            ) : (
                                filteredSessions.map((ritual) => (
                                    <tr key={ritual.id} className="hover:bg-white/[0.02] transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-4">
                                                <div className="w-10 h-10 rounded-lg bg-white/5 border border-white/5 p-1 shrink-0">
                                                    <img src={ritual.user?.avatar || `https://ui-avatars.com/api/?name=${ritual.user?.name}&background=3B82F6&color=FFFFFF`} className="w-full h-full rounded shadow-sm" alt="" />
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-bold text-white/90">{ritual.user?.name}</span>
                                                    <span className="text-[10px] text-white/30">{ritual.user?.phone || 'Private'}</span>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
