                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <p className="text-center text-[9px] font-sans font-semibold tracking-[0.5em] text-white/5 italic">
                    Universal Surveillance Layer • Real-time Monitoring Active
