                        >
                            <UserPlus size={16} /> Add Expert
                        </button>

                        {/* Role Tabs */}
                        <div className="flex p-1 bg-white/5 border border-white/5 rounded-2xl w-full sm:w-auto overflow-x-auto scrollbar-hide">
