            setIsOnline(data.expert.isOnline);
            setSessions(data.expert.chatSessions || []);

            // SRS §8.4 — Detect if profile is just a draft (needs onboarding)
            if (!data.expert || !data.expert.bio) {
                setNeedsOnboarding(true);
